<!DOCTYPE html><html lang="zxx">@include('layout.header')<body style="background:#0f172a;color:#e2e8f0;">    @include('layout.headerNav')    <canvas id="svcCanvas" style="position:fixed;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;"></canvas>    <div style="position:relative;z-index:1;padding-top:70px;">        <div style="max-width:1200px;margin:0 auto;padding:60px 20px 80px;">            <div style="text-align:center;margin-bottom:20px;">                <span style="display:inline-block;background:rgba(34,197,94,0.1);color:#22c55e;font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:2px;padding:6px 16px;border-radius:50px;margin-bottom:14px;">Services</span>                <h1 style="font-size:42px;font-weight:800;color:#ffffff;margin:0;letter-spacing:-1px;">What <span style="color:#22c55e;">We Offer</span></h1>                <p style="font-size:16px;color:#64748b;max-width:500px;margin:10px auto 0;">Comprehensive digital solutions tailored to your business needs.</p>            </div>        </div>    </div>    @include('frontend.components.services')    @include('layout.footer')    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js" defer></script>    <script>    (function(){var c=document.getElementById('svcCanvas');if(!c)return;        var s=new THREE.Scene(),a=new THREE.PerspectiveCamera(60,innerWidth/innerHeight,0.1,1e3),r=new THREE.WebGLRenderer({canvas:c,alpha:true,antialias:true});        r.setSize(innerWidth,innerHeight);r.setPixelRatio(Math.min(devicePixelRatio,2));        var p=new Float32Array(200*3);for(var i=0;i<200;i++){p[i*3]=(Math.random()-.5)*30;p[i*3+1]=(Math.random()-.5)*30;p[i*3+2]=(Math.random()-.5)*20}        var g=new THREE.BufferGeometry();g.setAttribute('position',new THREE.BufferAttribute(p,3));        s.add(new THREE.Points(g,new THREE.PointsMaterial({color:0x22c55e,size:0.025,transparent:true,opacity:0.3,blending:THREE.AdditiveBlending})));        var m=[];for(var i=0;i<6;i++){var h=Math.random()>.5?new THREE.IcosahedronGeometry(.08+Math.random()*.12):new THREE.TorusGeometry(.12+Math.random()*.1,.02,8,16);        var t=new THREE.MeshBasicMaterial({color:[0x22c55e,0x16a34a,0x4ade80][Math.floor(Math.random()*3)],wireframe:true,transparent:true,opacity:.06+Math.random()*.1});        var e=new THREE.Mesh(h,t);e.position.set((Math.random()-.5)*18,(Math.random()-.5)*18,(Math.random()-.5)*12-3);        e.rotation.set(Math.random()*Math.PI,Math.random()*Math.PI,0);        e.userData={rot:{x:(Math.random()-.5)*.005,y:(Math.random()-.5)*.005},baseY:e.position.y,phase:Math.random()*Math.PI*2};        s.add(e);m.push(e)}        a.position.z=6;var mx=0,my=0;document.addEventListener('mousemove',function(e){mx=(e.clientX/innerWidth)*2-1;my=-(e.clientY/innerHeight)*2+1});        var t=0;!function n(){requestAnimationFrame(n);t+=.005;        m.forEach(function(m){m.rotation.x+=m.userData.rot.x;m.rotation.y+=m.userData.rot.y;m.position.y=m.userData.baseY+Math.sin(t*4+m.userData.phase)*.12});        a.position.x+=(mx*.4-a.position.x)*.02;a.position.y+=(-my*.3-a.position.y)*.02;a.lookAt(s.position);r.render(s,a)}();        addEventListener('resize',function(){a.aspect=innerWidth/innerHeight;a.updateProjectionMatrix();r.setSize(innerWidth,innerHeight)});    })();    </script></body></html>
